const a = [
  {"id":2596,"text":"Which of the following is the end-product of purine metabolism?","explanation":null,"reference":"Barr WG. Uric Acid. In: Walker HK, Hall WD, Hurst JW, editors. Clinical Methods: The History, Physical, and Laboratory Examinations. 3rd edition. Boston: Butterworths; 1990. Chapter 165. Available from: https://www.ncbi.nlm.nih.gov/books/NBK273/","responses":[{"text":"Uric acid","correct":true,"visible":false},{"text":"Ammonia","correct":false,"visible":false},{"text":"Guanine","correct":false,"visible":false},{"text":"Uracil","correct":false,"visible":false},{"text":"Urea","correct":false,"visible":false}]},{"id":4770,"text":"The nephron is the functional unit of the kidney responsible for the filtration of plasma. It consists of which two major components?","explanation":null,"reference":null,"responses":[{"text":"Proximal convoluted tubule and distal convoluted tubule","correct":false,"visible":false},{"text":"Renal corpuscle and loop of Henle","correct":false,"visible":false},{"text":"Renal tubule and collecting tubule","correct":false,"visible":false},{"text":"Renal corpuscle and renal tubule","correct":true,"visible":false},{"text":"Proximal convoluted tubule and loop of Henle","correct":false,"visible":false}]},{"id":6269,"text":"What is the value of the glomerular filtration rate below which it is classified as an end-stage renal disease (ESRD)?","explanation":null,"reference":null,"responses":[{"text":"60 mL/min","correct":false,"visible":false},{"text":"30 mL/min","correct":false,"visible":false},{"text":"75 mL/min","correct":false,"visible":false},{"text":"15 mL/min","correct":true,"visible":false},{"text":"45 mL/min","correct":false,"visible":false}]},{"id":6275,"text":"Which of the following is a carbonic anhydrase inhibitor?","explanation":null,"reference":null,"responses":[{"text":"Torsemide","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Acetazolamide","correct":true,"visible":false},{"text":"Furosemide","correct":false,"visible":false},{"text":"Bumetanide","correct":false,"visible":false}]},{"id":6345,"text":"Which of the following parts of the nephron is involved in the facultative reabsorption of water?","explanation":null,"reference":null,"responses":[{"text":"Bowman's capsule","correct":false,"visible":false},{"text":"Loop of Henle","correct":false,"visible":false},{"text":"Duct of Bellini","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Proximal convoluted tubule","correct":false,"visible":false}]},{"id":6497,"text":"A 10-year-old girl complained of increasing fatigue and passing dark-colored urine for one week. She had a sore throat two weeks ago. On physical examination, there is no fever, and blood pressure is 140/90 mmHg. Laboratory studies show her serum creatinine is 2.8 mg/dL and urea nitrogen 24 mg/dL. Urinalysis shows 2+ blood, 1+ protein, no glucose, and no ketones. Microscopic urinalysis shows dysmorphic RBCs. A renal biopsy on microscopic examination shows glomerular hypercellularity, with polymorphonuclear leukocytes (PMNs) present. Electron microscopy shows subepithelial electron-dense humps. Which of the following laboratory findings is most likely to be present in this girl?","explanation":null,"reference":null,"responses":[{"text":"Antibody to double stranded DNA","correct":false,"visible":false},{"text":"Elevated antistreptolysin O (ASO) titer","correct":true,"visible":false},{"text":"Anti-glomerular basement membrane antibody","correct":false,"visible":false},{"text":"Elevated serum glucose","correct":false,"visible":false},{"text":"Positive C3 nephritogenic factor","correct":false,"visible":false}]},{"id":6498,"text":"A 38-year-old woman came with severe suprapubic pain. Urine analysis showed neutrophils without a cast, cloudy, and foul-smelling urine. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Hydronephrosis","correct":false,"visible":false},{"text":"Acute cystitis","correct":true,"visible":false},{"text":"Chronic cystitis","correct":false,"visible":false},{"text":"Acute pyelonephritis","correct":false,"visible":false},{"text":"Chronic pyelonephritis","correct":false,"visible":false}]},{"id":6505,"text":"A 10-year-boy is admitted to the ward with the complaint of urinary retention. A Foley catheter is passed to relieve the retention. How much length of catheter should be inserted before inflating the balloon of catheter?","explanation":null,"reference":null,"responses":[{"text":"3-5 cm of catheter length","correct":false,"visible":false},{"text":"When the urine starts flowing","correct":false,"visible":false},{"text":"Half the length of catheter","correct":false,"visible":false},{"text":"Just tip of the catheter","correct":false,"visible":false},{"text":"Entire length of the catheter","correct":true,"visible":false}]},{"id":6506,"text":"A second-year medical student is looking at the histology slide of tissue with small-caliber lined by transitional epithelium and also observes three layers of smooth muscles in its wall.  He is looking at a slide of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Vas deferens","correct":false,"visible":false},{"text":"Urethra","correct":false,"visible":false},{"text":"Ureter","correct":true,"visible":false},{"text":"Prostate","correct":false,"visible":false},{"text":"Urinary bladder","correct":false,"visible":false}]},{"id":6509,"text":"A 30-year-old pregnant lady is going for an emergency cesarean section. She is being catheterized before the procedure. Which one is the most recurrent complication of urinary catheterization?","explanation":null,"reference":null,"responses":[{"text":"Pyelonephritis","correct":false,"visible":false},{"text":"Urinary tract infection","correct":true,"visible":false},{"text":"Nephrolithiasis","correct":false,"visible":false},{"text":"Renal inflammation","correct":false,"visible":false},{"text":"Tissue trauma","correct":false,"visible":false}]},{"id":6514,"text":"A 32-year-old lady comes to the ultrasound department for an antenatal scan which shows bilateral hydronephrosis, hydro-ureters, and a distended urinary bladder with a keyhole sign in the fetus. The fetus is suspected with a case of posterior urethral valves. She is advised to have a post-natal checkup of the baby. What is the investigation of choice in this particular case?","explanation":null,"reference":"Bingham G, Rentea RM. Posterior urethral valve. In: StatPearls. StatPearls Publishing; 2022. Accessed October 17, 2022. http://www.ncbi.nlm.nih.gov/books/NBK560881/","responses":[{"text":"Kidney, ureter, and bladder (KUB) X-ray","correct":false,"visible":false},{"text":"Voiding cystourethrogram (VCUG)","correct":true,"visible":false},{"text":"Computed tomography scan (CT scan)","correct":false,"visible":false},{"text":"Repeat ultrasound KUB + Prostate","correct":false,"visible":false},{"text":"Magnetic resonance imaging (MRI)","correct":false,"visible":false}]},{"id":6516,"text":"Which of the following is a complication of acute pyelonephritis?","explanation":null,"reference":null,"responses":[{"text":"Papillary necrosis","correct":true,"visible":false},{"text":"Necrotic syndrome","correct":false,"visible":false},{"text":"Cholecystitis","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false},{"text":"Chronic renal faillure","correct":false,"visible":false}]},{"id":6517,"text":"A 35-year-old male presents with features of nephrotic syndrome. In addition, there is microscopic haematuria. Renal biopsy shows partial sclerosis affecting some of the glomeruli. Sclerosed areas show IgM and C3 on immunofluorescence. What is the most likely diagnosis in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 916.","responses":[{"text":"Membranous nephropathy","correct":false,"visible":false},{"text":"Acute post infectious glomerulonephritis","correct":false,"visible":false},{"text":"Minimal change disease","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":true,"visible":false},{"text":"IgA nephropathy","correct":false,"visible":false}]},{"id":6518,"text":"A 4-year-old girl presents with severe pitting edema. Further investigations show hypoalbuminemia, lipiduria, and 3.8 g proteinuria. Biopsy confirms the renal disease. Which of the following best describes the pathophysiology of proteinuria in this patient?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 128.","responses":[{"text":"Anti–glomerular basement membrane (anti-GBM) antibodies cross reacting with alveolar basement membranes","correct":false,"visible":false},{"text":"Crescent formation in the glomeruli","correct":false,"visible":false},{"text":"Excess dietary protein intake","correct":false,"visible":false},{"text":"Tubulointerstitial damage","correct":false,"visible":false},{"text":"Derangement in glomerular capillary walls","correct":true,"visible":false}]},{"id":6519,"text":"A 4-year-old girl is brought to the hospital with complaints of continuous dribbling of urine. On examination, the urine was coming out of the vagina. The possible cause of this embryological anomaly may be due to which of these?","explanation":null,"reference":null,"responses":[{"text":"Formation of vaginal fistula","correct":true,"visible":false},{"text":"Ureter opening into the base of urinary bladder","correct":false,"visible":false},{"text":"Ureter opening into the urogenital sinus","correct":false,"visible":false},{"text":"Ureter opening into cloaca","correct":false,"visible":false},{"text":"Ureter opening into paramesonephric duct","correct":false,"visible":false}]},{"id":6530,"text":"Which of the following is formed as a result of deamination of cytosine?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 428.","responses":[{"text":"Adenine","correct":false,"visible":false},{"text":"Methyl cytosine","correct":false,"visible":false},{"text":"Cytidylic acid","correct":false,"visible":false},{"text":"Uracil","correct":true,"visible":false},{"text":"Tyrosine","correct":false,"visible":false}]},{"id":6544,"text":"Which of the following clinical symptoms differentiates pyelonephritis from cystitis?","explanation":null,"reference":null,"responses":[{"text":"Dysuria","correct":false,"visible":false},{"text":"Hematuria","correct":false,"visible":false},{"text":"Fever","correct":true,"visible":false},{"text":"Polyuria","correct":false,"visible":false},{"text":"Anemia","correct":false,"visible":false}]},{"id":6545,"text":"Which of the following is a method to excrete excess water?","explanation":null,"reference":null,"responses":[{"text":"Increased respiratory rate","correct":false,"visible":false},{"text":"Diarrhea","correct":false,"visible":false},{"text":"Polyuria","correct":true,"visible":false},{"text":"Oliguria","correct":false,"visible":false},{"text":"Sweating","correct":false,"visible":false}]},{"id":6549,"text":"A 40-year-old businesswoman came to the outpatient department for the workup of her recurrent renal stone disease. She has already undergone multiple investigations and now she is insisting to go for magnetic resonance imaging (MRI). How will you counsel her that for her particular disease, MRI is not a suitable modality?","explanation":null,"reference":null,"responses":[{"text":"MRI works under the principle of magnetism","correct":false,"visible":false},{"text":"No ionization radiation burden is present in MRI","correct":false,"visible":false},{"text":"MRI is an expensive modality","correct":false,"visible":false},{"text":"MRI reporting is difficult","correct":false,"visible":false},{"text":"Calcification/calcific densities are detected with difficulty by MRI","correct":true,"visible":false}]},{"id":6553,"text":"A 2nd-year student is studying kidney anatomy and finds out that there are some structures anterior to the right kidney. Which of the following is not found anterior to the right kidney?","explanation":null,"reference":null,"responses":[{"text":"Pylorus","correct":true,"visible":false},{"text":"2nd part of duodenum","correct":false,"visible":false},{"text":"Hepatic flexure","correct":false,"visible":false},{"text":"Right colic flexure","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false}]},{"id":6555,"text":"A 43-year-old man complains of malaise for 3 weeks. On examination, his blood pressure is 150/95 mm Hg, and presents with pitting edema of the lower extremities. Urinalysis shows no glucose, blood, ketones, nitrite, or urobilinogen, and the microscopic urinalysis reveals no RBC/HPF and only 1 WBC/HPF, 24-hour urine protein is 4.1 gm, serum creatinine is 3.5 mg/dL with urea nitrogen of 38 mg/dL. His hepatitis B surface antigen is positive. Which of the following is the most likely diagnosis in this patient?","explanation":null,"reference":null,"responses":[{"text":"Membranous nephropathy","correct":true,"visible":false},{"text":"Diabetic nephropathy","correct":false,"visible":false},{"text":"Systemic lupus erythematosus","correct":false,"visible":false},{"text":"Post streptococcal glomerulonephritis","correct":false,"visible":false},{"text":"Acute tubular necrosis","correct":false,"visible":false}]},{"id":6556,"text":"A 5-year-old boy presents with generalized edema and periorbital edema. Further investigations show hypoalbuminemia, lipiduria, and 3.7 g proteinuria. Which of the following conditions is the most likely cause in this patient?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 127.","responses":[{"text":"Rapidly progressive glomerulonephritis","correct":false,"visible":false},{"text":"IgA nephropathy","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":false,"visible":false},{"text":"Minimal change disease","correct":true,"visible":false},{"text":"Amyloidosis","correct":false,"visible":false}]},{"id":6557,"text":"A 5-year-old boy has had swelling around his eyes for one week, and he has been lethargic. On examination, he has periorbital edema. His temperature is 37°C, pulse is 75 bpm, respiratory rate is 22/minute, and blood pressure is 140/90 mmHg. Urine examination shows a specific gravity of 1.010 and a pH of 6.5, with 4+ protein, no glucose, no blood, no casts, and no ketones. Microscopic urinalysis exhibits fat bodies, but no leukocytes or erythrocytes. He improves with corticosteroid therapy. Which of the following is the most likely lesion in the kidney?","explanation":null,"reference":null,"responses":[{"text":"Hyperplastic arteriosclerosis","correct":false,"visible":false},{"text":"Glomerular crescent formation","correct":false,"visible":false},{"text":"Immune complex deposition in the mesangium","correct":false,"visible":false},{"text":"Acute tubular necrosis","correct":false,"visible":false},{"text":"Effacement of podocyte foot processes","correct":true,"visible":false}]},{"id":6559,"text":"During degradation of purine nucleotides to uric acid, inosine monophosphate and guanosine monophosphate are broken down by which of the following enzymes?","explanation":null,"reference":null,"responses":[{"text":"Ribonucleotide reductase","correct":false,"visible":false},{"text":"Adenosine deaminase","correct":false,"visible":false},{"text":"Xanthine oxidase","correct":false,"visible":false},{"text":"5'-nucleotidase","correct":true,"visible":false},{"text":"Guanylate kinase","correct":false,"visible":false}]},{"id":6560,"text":"Aspartate enters the tricarboxylic acid cycle (TCA cycle) in the form of which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 109.","responses":[{"text":"Oxaloacetate","correct":true,"visible":false},{"text":"Succinic acid","correct":false,"visible":false},{"text":"Alpha-ketoglutarate","correct":false,"visible":false},{"text":"Citrate","correct":false,"visible":false},{"text":"Fumarate","correct":false,"visible":false}]},{"id":6562,"text":"Which of the following is the most common cause of pyelonephritis?","explanation":null,"reference":null,"responses":[{"text":"Staphylococcus saprophyticus","correct":false,"visible":false},{"text":"Klebsiella species","correct":false,"visible":false},{"text":"E. coli","correct":true,"visible":false},{"text":"Enterococcus faecalis","correct":false,"visible":false},{"text":"Proteus mirabilis","correct":false,"visible":false}]},{"id":6575,"text":"A 6-year-old boy presents with generalized edema and periorbital edema. Further investigations show hypoalbuminemia, lipiduria, and 3.6 g proteinuria. Renal biopsy and electron microscopy are carried out. Which of the following electron microscopic features do you expect to find in this patient?","explanation":null,"reference":null,"responses":[{"text":"Subepithelial humps","correct":false,"visible":false},{"text":"Loss of foot processes, no deposits","correct":true,"visible":false},{"text":"Dense mesangial deposits","correct":false,"visible":false},{"text":"Subendothelial deposits","correct":false,"visible":false},{"text":"Linear deposits of IgG in the glomerular basement membrane","correct":false,"visible":false}]},{"id":6591,"text":"Synthetic compound allopurinol given to treat hyperuricemia is an analog of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Cytosine","correct":false,"visible":false},{"text":"Hypoxanthine","correct":true,"visible":false},{"text":"Orotic acid","correct":false,"visible":false},{"text":"Thymine","correct":false,"visible":false},{"text":"Inosine","correct":false,"visible":false}]},{"id":6592,"text":"Which of the following is diagnostic of acute gout?","explanation":null,"reference":null,"responses":[{"text":"Acute phase reactants","correct":false,"visible":false},{"text":"Monosodium urate crystals on joint aspiration","correct":true,"visible":false},{"text":"Magnetic resonance imaging","correct":false,"visible":false},{"text":"Serum uric acid levels","correct":false,"visible":false},{"text":"Radiology of joint","correct":false,"visible":false}]},{"id":6626,"text":"A child after a streptococcal infection presents 10 days later with hypertension, hematuria, edema, and sometimes oliguria. There appear to be elevated titers of anti-streptolysin O antibodies. What is the key morphological feature of his disease?","explanation":null,"reference":null,"responses":[{"text":"Humps and deposition of IgG and C3","correct":true,"visible":false},{"text":"Humps","correct":false,"visible":false},{"text":"Deposition of IgG and C3","correct":false,"visible":false},{"text":"Deposition of IgM and C3","correct":false,"visible":false},{"text":"Spike and dome appearance","correct":false,"visible":false}]},{"id":6644,"text":"A filterability of 1.0 means that the substance is filtered as freely as water, whereas a filterability of 0.75 means that the substance is filtered only 75%. Which of the following substance has a filterability of only 75 percent as rapidly as water?","explanation":null,"reference":null,"responses":[{"text":"Albumin","correct":false,"visible":false},{"text":"Sodium","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false},{"text":"Myoglobin","correct":true,"visible":false},{"text":"Inulin","correct":false,"visible":false}]},{"id":6645,"text":"A normal 70 kg human must excrete about how many milliosmoles of solute each day?","explanation":null,"reference":null,"responses":[{"text":"400","correct":false,"visible":false},{"text":"200","correct":false,"visible":false},{"text":"1000","correct":false,"visible":false},{"text":"600","correct":true,"visible":false},{"text":"800","correct":false,"visible":false}]},{"id":6658,"text":"What is the research study design in which diseased people are selected and then compared with the non-diseased people to find out the risk factors of the disease called?","explanation":null,"reference":null,"responses":[{"text":"Cross-sectional study","correct":false,"visible":false},{"text":"Case report study","correct":false,"visible":false},{"text":"Case control study","correct":true,"visible":false},{"text":"Cohort study","correct":false,"visible":false},{"text":"Case series study","correct":false,"visible":false}]},{"id":6659,"text":"What is a water molecule with an electrical charge distributed asymmetrically about its structure referred to as?","explanation":null,"reference":null,"responses":[{"text":"Pentapolar","correct":false,"visible":false},{"text":"Unipolar","correct":false,"visible":false},{"text":"Tripolar","correct":false,"visible":false},{"text":"Dipolar","correct":true,"visible":false},{"text":"Tetrapolar","correct":false,"visible":false}]},{"id":6660,"text":"A young male presented in a dehydrated state of moderate degree. His renal function is normal but he is unable to take fluid orally because of drowsiness and vomiting. Which of the following intravenous fluids is preferable to start first?","explanation":null,"reference":null,"responses":[{"text":"3% saline","correct":false,"visible":false},{"text":"Distilled water","correct":false,"visible":false},{"text":"1/3 saline","correct":false,"visible":false},{"text":"Ringer's lactate","correct":false,"visible":false},{"text":"5% dextrose","correct":true,"visible":false}]},{"id":6661,"text":"About 35% of the filtered load of sodium chloride is reabsorbed from which part of the nephron?","explanation":null,"reference":null,"responses":[{"text":"Thin limb - loop of Henle","correct":false,"visible":false},{"text":"Collecting duct","correct":false,"visible":false},{"text":"Cortical collecting tubule","correct":false,"visible":false},{"text":"Thick ascending limb of loop of Henle","correct":true,"visible":false},{"text":"Distal convoluted tubule","correct":false,"visible":false}]},{"id":6662,"text":"Amina has recently completed her FCPS and now she is pursuing her career as a specialist. She was passionate about this field and always wanted to serve society and live a meaningful life. Which of the following approach of happiness most likely focuses on meaning and self-realization?","explanation":null,"reference":"The best within us: positive psychology perspectives on eudaimonia. https://www.apa.org. Accessed October 19, 2022. https://www.apa.org/pubs/books/4318113","responses":[{"text":"Psychological well-being","correct":false,"visible":false},{"text":"Eudemonia","correct":true,"visible":false},{"text":"Hedonism","correct":false,"visible":false},{"text":"Happiness","correct":false,"visible":false},{"text":"Subjective well being","correct":false,"visible":false}]},{"id":6663,"text":"What is the alkaline nature of the extracellular fluid and acidic urine termed as?","explanation":null,"reference":"Schoaps RS, Hazard SW, Docimo Jr. S, Pauli EM. Paradoxical aciduria. Clinical Algorithms in General Surgery : A Practical Guide. https://link.springer.com/chapter/10.1007/978-3-319-98497-1_188","responses":[{"text":"Phenyl ketonuria","correct":false,"visible":false},{"text":"Paradoxical aciduria","correct":true,"visible":false},{"text":"Amino aciduria","correct":false,"visible":false},{"text":"Glucosuria","correct":false,"visible":false},{"text":"Ketonuria","correct":false,"visible":false}]},{"id":6671,"text":"An adult male had a road traffic accident and went into a hypovolemic shock due to blood loss. Which intravenous fluid is preferable to start as initial available therapy in an emergency?","explanation":null,"reference":"Haemaccel - summary of product characteristics (Smpc) -(Emc). Accessed October 19, 2022. https://www.medicines.org.uk/emc/product/13176/smpc#gref","responses":[{"text":"Albumin","correct":false,"visible":false},{"text":"Haemaccel","correct":true,"visible":false},{"text":"Ringer's lactate","correct":false,"visible":false},{"text":"Amino acid solution","correct":false,"visible":false},{"text":"5% dextrose water","correct":false,"visible":false}]},{"id":6673,"text":"In chronic renal failure, anemia develops due to which of the following?","explanation":null,"reference":null,"responses":[{"text":"Erythropoetin deficiency","correct":true,"visible":false},{"text":"Blood loss","correct":false,"visible":false},{"text":"Bone marrow toxins","correct":false,"visible":false},{"text":"Red cell destruction","correct":false,"visible":false},{"text":"Bone marrow fibrosis","correct":false,"visible":false}]},{"id":6675,"text":"Considering the normal urine composition, what is the water content of it in percentage?","explanation":null,"reference":null,"responses":[{"text":"75%","correct":false,"visible":false},{"text":"95%","correct":true,"visible":false},{"text":"85%","correct":false,"visible":false},{"text":"80%","correct":false,"visible":false},{"text":"90%","correct":false,"visible":false}]},{"id":6676,"text":"A decrease in sodium chloride levels causes the macula densa to do which of the following?","explanation":null,"reference":null,"responses":[{"text":"Dilatation of efferent arterioles","correct":false,"visible":false},{"text":"Contraction of juxtaglomerular cells","correct":false,"visible":false},{"text":"Dilatation of afferent arterioles","correct":true,"visible":false},{"text":"Contraction of mesangial cells","correct":false,"visible":false},{"text":"Inhibition of renin","correct":false,"visible":false}]},{"id":6677,"text":"Disturbance in the renal reabsorption of bicarbonates in the proximal tubules leads to which one of the following?","explanation":"In the kidneys, bicarbonate (HCO₃⁻) reabsorption in the proximal tubules is a primary mechanism for conserving the body's bicarbonate and thus maintaining the pH of body fluids. Disturbances in the renal reabsorption of bicarbonate in the proximal tubules can lead to its excessive loss in the urine. This loss of bicarbonate decreases the buffering capacity of the blood, resulting in **metabolic acidosis**. Metabolic acidosis is characterized by a decrease in plasma bicarbonate concentration and a decrease in arterial blood pH. Other potential causes of metabolic acidosis include excess acid production (like lactic acidosis) and inability to excrete acid (renal failure). However, when bicarbonate reabsorption is specifically disturbed in the proximal tubules, loss of this essential buffer results in metabolic acidosis.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 415.","responses":[{"text":"Metabolic acidosis","correct":true,"visible":false},{"text":"Nitrogen retention","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Hypochloremia","correct":false,"visible":false},{"text":"Acidic urine","correct":false,"visible":false}]},{"id":6678,"text":"During a tutorial class on the microscopic structure of the kidney, specific features of each part of the nephron were being discussed. Which of the following is mismatched?","explanation":null,"reference":null,"responses":[{"text":"Visceral layer of Bowman's capsule - podocytes","correct":false,"visible":false},{"text":"Thin segment of Henle's loop - simple squamous epithelium","correct":false,"visible":false},{"text":"Proximal tubule cells - many mitochondria; an ion-pumping cell","correct":false,"visible":false},{"text":"Parietal layer of Bowman's capsule - simple squamous epithelium","correct":false,"visible":false},{"text":"Distal tubule cells - brush border","correct":true,"visible":false}]},{"id":6679,"text":"Which is true about creatinine during glomerular filtration at normal levels?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 361.","responses":[{"text":"Secreted by the tubule","correct":true,"visible":false},{"text":"Excreted by the tubule","correct":false,"visible":false},{"text":"Neither secreted nor reabsorbed by the tubule","correct":false,"visible":false},{"text":"Secreted and reabsorbed by the tubule","correct":false,"visible":false},{"text":"Reabsorbed by the tubule","correct":false,"visible":false}]},{"id":6680,"text":"Which one of the following is true about the epithelium of navicular fossa of glans penis?","explanation":null,"reference":null,"responses":[{"text":"Pseudostratified epithelium","correct":false,"visible":false},{"text":"Simple squamous epithelium","correct":false,"visible":false},{"text":"Columnar epithelium","correct":false,"visible":false},{"text":"Stratified squamous keratinizing epithelium","correct":false,"visible":false},{"text":"Stratified squamous non-keratinizing epithelium","correct":true,"visible":false}]},{"id":6681,"text":"Which of the following factor causes an increase in the secretion of antidiuretic hormone (ADH)?","explanation":null,"reference":null,"responses":[{"text":"Decrease in plasma osmolarity","correct":false,"visible":false},{"text":"Increase in blood pressure","correct":false,"visible":false},{"text":"Hyponatremia","correct":false,"visible":false},{"text":"Intake of alcohol","correct":false,"visible":false},{"text":"Decrease in blood volume","correct":true,"visible":false}]},{"id":6682,"text":"Which of the following is true regarding acute kidney injury (AKI)?","explanation":null,"reference":null,"responses":[{"text":"Often reversible","correct":true,"visible":false},{"text":"Calcium levels are high","correct":false,"visible":false},{"text":"Always needs dialysis","correct":false,"visible":false},{"text":"Ultrasound shows small kidneys","correct":false,"visible":false},{"text":"Anemia is a predominant feature","correct":false,"visible":false}]},{"id":6683,"text":"Where does the hilum of the left kidney lie?","explanation":null,"reference":null,"responses":[{"text":"The subcostal plane","correct":false,"visible":false},{"text":"The interspinous plane","correct":false,"visible":false},{"text":"The junction of midclavicular line and the transtubercular plane","correct":false,"visible":false},{"text":"The transpyloric plane, 5 cm from the median plane","correct":true,"visible":false},{"text":"The transtubercular plane, 5 cm from the median plane","correct":false,"visible":false}]},{"id":6684,"text":"If plasma colloidal osmotic pressure is 40 mmHg, renal capillary pressure is 60 mmHg, and Bowman's capsule hydrostatic pressure is 18 mmHg, which of the following effect occurs in the kidney?","explanation":"The net filtration pressure (NFP) in the glomerulus is determined by the balance between forces promoting filtration (renal capillary pressure) and those opposing filtration (plasma colloidal osmotic pressure and Bowman's capsule hydrostatic pressure). \r\n\r\nNFP = Renal capillary pressure - (Plasma colloidal osmotic pressure + Bowman's capsule hydrostatic pressure)\r\nNFP = 60 mmHg - (40 mmHg + 18 mmHg) = 2 mmHg\r\n\r\nTypically, a positive NFP is required for glomerular filtration to occur. Given the provided pressures, the NFP is reduced to only 2 mmHg. A decreased NFP translates to a **reduced glomerular filtration rate (GFR)**. This means less plasma is filtered through the glomeruli, reducing the volume of filtrate produced and eventually reducing urine output.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 334.","responses":[{"text":"Afferent arteriolar dilatation","correct":false,"visible":false},{"text":"Efferent arteriolar dilatation","correct":false,"visible":false},{"text":"Contraction of macula densa","correct":false,"visible":false},{"text":"Glomerular filtration rate (GFR) is increased","correct":false,"visible":false},{"text":"Glomerular filtration rate (GFR) is reduced","correct":true,"visible":false}]},{"id":6685,"text":"In a 60-year-old diabetic patient, a routine lab investigation shows hemoglobin: 8.2 gm/dL, creatinine (Cr): 5.0 mg/dL, calcium (Ca): 6.7 mg/dL, phosphate(PO4): 5.2 mg/dL, with small kidneys on ultrasound. What is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 132, 133.","responses":[{"text":"Glomerulonephritis","correct":false,"visible":false},{"text":"Urinary tract infection","correct":false,"visible":false},{"text":"Acute kidney injury","correct":false,"visible":false},{"text":"Acute interstitial nephritis","correct":false,"visible":false},{"text":"Chronic kidney disease","correct":true,"visible":false}]},{"id":6686,"text":"In a patient with severe dehydration, the plasma osmolality increases. This is corrected by which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 233.","responses":[{"text":"Aldosterone","correct":false,"visible":false},{"text":"Antidiuretic hormone (ADH)","correct":true,"visible":false},{"text":"Increase in protein intake","correct":false,"visible":false},{"text":"Angiotensin-II","correct":false,"visible":false},{"text":"Increased intake of glucose","correct":false,"visible":false}]},{"id":6687,"text":"Which one of the following correctly states the osmolarity of the fluid entering  the proximal convoluted tubules?","explanation":null,"reference":null,"responses":[{"text":"400 mOsm/L","correct":false,"visible":false},{"text":"800 mOsm/L","correct":false,"visible":false},{"text":"300 mOsm/L","correct":true,"visible":false},{"text":"1200 mOsm/L","correct":false,"visible":false},{"text":"100 mOsm/L","correct":false,"visible":false}]},{"id":6688,"text":"Which of these is present on urinalysis in a patient with glomerulonephritis?","explanation":null,"reference":null,"responses":[{"text":"Hyaline cast","correct":false,"visible":false},{"text":"Granular cast","correct":false,"visible":false},{"text":"Red cell cast","correct":true,"visible":false},{"text":"Renal tubular cell cast","correct":false,"visible":false},{"text":"White cell cast","correct":false,"visible":false}]},{"id":6689,"text":"Which of the following is true for the overhydration state?","explanation":null,"reference":null,"responses":[{"text":"Osmotic pressure increases in extracellular fluid","correct":false,"visible":false},{"text":"Hypothalamus signals posterior pituitary to increase ADH (antidiuretic hormone) output","correct":false,"visible":false},{"text":"Osmoreceptors in hypothalamus are stimulated","correct":false,"visible":false},{"text":"Urine output decreases","correct":false,"visible":false},{"text":"Hypothalamus signals posterior pituitary to decrease ADH (antidiuretic hormone) output","correct":true,"visible":false}]},{"id":6690,"text":"In pyelonephritis, what is the diagnostic urinary finding?","explanation":null,"reference":null,"responses":[{"text":"Pus cell cast","correct":true,"visible":false},{"text":"Pus cells","correct":false,"visible":false},{"text":"Red blood cell cast","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false},{"text":"Red blood cells","correct":false,"visible":false}]},{"id":6692,"text":"Which one of the following is the approximate value of the osmolarity of the interstitial fluid in renal medulla?","explanation":null,"reference":null,"responses":[{"text":"600 mOsm/L","correct":false,"visible":false},{"text":"1200 mOsm/L","correct":true,"visible":false},{"text":"200 mOsm/L","correct":false,"visible":false},{"text":"800 mOsm/L","correct":false,"visible":false},{"text":"400 mOsm/L","correct":false,"visible":false}]},{"id":6693,"text":"Which one of the following confirms the diagnosis of gout?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 1014.","responses":[{"text":"Increased uric acid excretion in urine","correct":false,"visible":false},{"text":"Redness and pain in joints","correct":false,"visible":false},{"text":"Presence of urate crystals in the synovial fluid","correct":true,"visible":false},{"text":"Renal stones","correct":false,"visible":false},{"text":"Hyperuricemia","correct":false,"visible":false}]},{"id":6694,"text":"In response to acidosis, the kidneys may enhance which of these?","explanation":null,"reference":null,"responses":[{"text":"Secretion of HCO3- ions","correct":false,"visible":false},{"text":"Nitrogen retention","correct":false,"visible":false},{"text":"Secretion of H+ ions","correct":true,"visible":false},{"text":"Secretion of Na+ ions","correct":false,"visible":false},{"text":"Secretion of K+ ions","correct":false,"visible":false}]},{"id":6695,"text":"In response to alkalosis, the kidneys may enhance which of these?","explanation":null,"reference":null,"responses":[{"text":"Nitrogen retention","correct":false,"visible":false},{"text":"Secretion of HCO3- ions","correct":true,"visible":false},{"text":"Secretion of H+ ions","correct":false,"visible":false},{"text":"Secretion of Na+ ions","correct":false,"visible":false},{"text":"Secretion of K+ ions","correct":false,"visible":false}]},{"id":6696,"text":"In a detailed urine report, dipstick mechanism checks for which of these?","explanation":null,"reference":null,"responses":[{"text":"Infecting organism","correct":false,"visible":false},{"text":"Protein and glucose","correct":true,"visible":false},{"text":"Casts","correct":false,"visible":false},{"text":"Crystals","correct":false,"visible":false},{"text":"Cells","correct":false,"visible":false}]},{"id":6697,"text":"Renal retention of which of these ions is directly linked to an increase in extracellular fluid volume?","explanation":null,"reference":null,"responses":[{"text":"K+ ions","correct":false,"visible":false},{"text":"Cl- ions","correct":false,"visible":false},{"text":"Na+ ions","correct":true,"visible":false},{"text":"HCO3- ions","correct":false,"visible":false},{"text":"H+ ions","correct":false,"visible":false}]},{"id":6698,"text":"What percentage of total body water is contained in the intracellular fluid?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 306.","responses":[{"text":"60%","correct":false,"visible":false},{"text":"30%","correct":false,"visible":false},{"text":"40%","correct":false,"visible":false},{"text":"50%","correct":false,"visible":false},{"text":"70%","correct":true,"visible":false}]},{"id":6699,"text":"Juxtaglomerular apparatus is a specialized structure located at the vascular pole of the glomerulus. Which of the following is true concerning the juxtaglomerular apparatus?","explanation":null,"reference":null,"responses":[{"text":"The macula densa is part of the proximal tubule","correct":false,"visible":false},{"text":"Lacis cells are the specialized smooth muscle cells","correct":true,"visible":false},{"text":"The juxtaglomerular (JG) cells are modified epithelial cells","correct":false,"visible":false},{"text":"The juxtaglomerular (JG) cells are found equally in both the afferent and efferent arterioles","correct":false,"visible":false},{"text":"Macula densa cells secrete renin","correct":false,"visible":false}]},{"id":6700,"text":"Juxtaglomerular apparatus is very important in blood pressure regulation. Which of the following structure is not its part?","explanation":null,"reference":null,"responses":[{"text":"Podocytes","correct":true,"visible":false},{"text":"Juxtaglomerular cells (JG) cells","correct":false,"visible":false},{"text":"Macula densa","correct":false,"visible":false},{"text":"Polkissen cells","correct":false,"visible":false},{"text":"Extra glomerular mesangial cells","correct":false,"visible":false}]},{"id":6701,"text":"Lymphatics of kidneys drain into which nodes?","explanation":null,"reference":null,"responses":[{"text":"Testicular nodes","correct":false,"visible":false},{"text":"Cystic nodes","correct":false,"visible":false},{"text":"Pre aortic nodes","correct":false,"visible":false},{"text":"Lateral aortic nodes","correct":true,"visible":false},{"text":"Superficial inguinal nodes","correct":false,"visible":false}]},{"id":6703,"text":"Which of the following organisms is responsible for xanthogranulomatous pyelonephritis?","explanation":null,"reference":null,"responses":[{"text":"Klebsiella","correct":false,"visible":false},{"text":"Salmonella","correct":false,"visible":false},{"text":"Proteus","correct":true,"visible":false},{"text":"Neisseria gonorrhoeae","correct":false,"visible":false},{"text":"E. coli","correct":false,"visible":false}]},{"id":6705,"text":"Which of the following does the least dilated part of male urethra develops from?","explanation":null,"reference":null,"responses":[{"text":"Fusion of urethral folds","correct":false,"visible":false},{"text":"Phallic part of urogenital sinus","correct":false,"visible":false},{"text":"Allantois","correct":false,"visible":false},{"text":"Pelvic part of urogenital sinus","correct":true,"visible":false},{"text":"Wolffian duct","correct":false,"visible":false}]},{"id":6706,"text":"Which of the following steps comes after data collection?","explanation":null,"reference":null,"responses":[{"text":"Formulate question","correct":false,"visible":false},{"text":"Hypothesis","correct":false,"visible":false},{"text":"Literature search","correct":false,"visible":false},{"text":"Development of research design","correct":false,"visible":false},{"text":"Data analysis","correct":true,"visible":false}]},{"id":6708,"text":"Which one of the following is the first step of research?","explanation":null,"reference":null,"responses":[{"text":"Literature search","correct":false,"visible":false},{"text":"Formulate questions","correct":false,"visible":false},{"text":"Hypothesis","correct":true,"visible":false},{"text":"Data collection","correct":false,"visible":false},{"text":"Develop research design","correct":false,"visible":false}]},{"id":6711,"text":"How are membranous glomerulopathy and post-streptococcal glomerulonephritis similar?","explanation":null,"reference":null,"responses":[{"text":"Both are self-limiting and transient renal diseases","correct":false,"visible":false},{"text":"Most commonly seen in children","correct":false,"visible":false},{"text":"Commonly associated with the nephrotic syndrome","correct":false,"visible":false},{"text":"Occur most frequently following an infectious disease","correct":false,"visible":false},{"text":"Glomerular immune complex deposits","correct":true,"visible":false}]},{"id":6712,"text":"In purine metabolism, what does the deamination of guanine yield?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 299.","responses":[{"text":"Cytidylic acid","correct":false,"visible":false},{"text":"Uracil","correct":false,"visible":false},{"text":"Xanthine","correct":true,"visible":false},{"text":"Methyl guanine","correct":false,"visible":false},{"text":"Thiamine","correct":false,"visible":false}]},{"id":6713,"text":"Increase in which of the following characterizes metabolic alkalosis?","explanation":null,"reference":null,"responses":[{"text":"Plasma pH and increased lactate levels","correct":false,"visible":false},{"text":"Plasma pH and decreased CO2 levels","correct":false,"visible":false},{"text":"Plasma pH and increased respiratory rate","correct":false,"visible":false},{"text":"Plasma pH and decrease in HCO3- levels","correct":false,"visible":false},{"text":"Plasma pH and increased plasma bicarbonate (HCO3-) levels","correct":true,"visible":false}]},{"id":6715,"text":"Mrs. X, a 30-year-old, recently married female, presented with a breast lump for the first time in the clinic. The doctor listened to her attentively but was insensitive towards her symptoms and complications. The doctor did not say or discuss anything but advised her to get the list of investigations done. She returned from the clinic more apprehensive and confused. What do you think, could most likely address her apprehensions?","explanation":null,"reference":null,"responses":[{"text":"An attribute of cultural sensitivity","correct":false,"visible":false},{"text":"An attribute of empathy","correct":false,"visible":false},{"text":"By arranging an information care session","correct":true,"visible":false},{"text":"By offering emotional support","correct":false,"visible":false},{"text":"By addressing her misconceptions","correct":false,"visible":false}]},{"id":6716,"text":"Mr. Mughees did not score well in the exam. He has pessimistic explanatory styles and attributed his failure to generalized bad luck i.e. 'I always had bad luck in all life situations' (stable and global attribution), which lead to him being depressed. Which one of the following could preferably explain the causes of negative events contrary to this pessimistic explanatory style?","explanation":null,"reference":null,"responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Internal, stable","correct":false,"visible":false},{"text":"Internal, specific, unstable","correct":true,"visible":false},{"text":"External, global, stable","correct":false,"visible":false},{"text":"External, unstable, specific","correct":false,"visible":false}]},{"id":6717,"text":"On discussing histological features of the kidney, the students were asked about the location of macula densa. What is its location?","explanation":null,"reference":null,"responses":[{"text":"Distal convoluted tubule","correct":true,"visible":false},{"text":"Renal pelvis","correct":false,"visible":false},{"text":"Collecting duct","correct":false,"visible":false},{"text":"Proximal convoluted tubule","correct":false,"visible":false},{"text":"Loop of Henle","correct":false,"visible":false}]},{"id":6719,"text":"Periureteric fascia is an extension of which of these?","explanation":null,"reference":null,"responses":[{"text":"Paranephric fat","correct":false,"visible":false},{"text":"Renal fascia","correct":true,"visible":false},{"text":"Perinephric fat","correct":false,"visible":false},{"text":"Pararenal fat","correct":false,"visible":false},{"text":"Perirenal fat","correct":false,"visible":false}]},{"id":6721,"text":"Which of the following is carbamoyl phosphate a precursor of?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 253.","responses":[{"text":"Xanthine","correct":false,"visible":false},{"text":"Uric acid","correct":false,"visible":false},{"text":"Hypoxanthine","correct":false,"visible":false},{"text":"Ionosine","correct":false,"visible":false},{"text":"Urea","correct":true,"visible":false}]},{"id":6722,"text":"What causes the reabsorption of bicarbonates from renal tubules?","explanation":null,"reference":null,"responses":[{"text":"Retention of acid metabolites","correct":false,"visible":false},{"text":"Low acid secretion","correct":false,"visible":false},{"text":"Raised PCO2","correct":true,"visible":false},{"text":"Decreased NH3 formation","correct":false,"visible":false},{"text":"Decreased PCO2","correct":false,"visible":false}]},{"id":6723,"text":"Reabsorption of sodium in renal tubules is associated with the exchange of which of these ions?","explanation":null,"reference":null,"responses":[{"text":"Na+ ions","correct":false,"visible":false},{"text":"HCO3- ions","correct":false,"visible":false},{"text":"H+ ions","correct":false,"visible":false},{"text":"K+ ions","correct":true,"visible":false},{"text":"Cl- ions","correct":false,"visible":false}]},{"id":6726,"text":"Which of the following is not true regarding blood supply to the kidneys?","explanation":null,"reference":null,"responses":[{"text":"Inter lobular arteries are end arteries","correct":false,"visible":false},{"text":"Afferent glomerular arterioles arise mostly form arcuate arteries","correct":true,"visible":false},{"text":"Renal circulation is of portal type","correct":false,"visible":false},{"text":"Kidney is divided into five vascular segments","correct":false,"visible":false},{"text":"Medulla receives blood mostly from efferent arterioles of glomeruli","correct":false,"visible":false}]},{"id":6727,"text":"What is the approximate length of kidney?","explanation":null,"reference":null,"responses":[{"text":"12 cm","correct":false,"visible":false},{"text":"10 cm","correct":true,"visible":false},{"text":"6-12 cm","correct":false,"visible":false},{"text":"8-9 cm","correct":false,"visible":false},{"text":"11-13 cm","correct":false,"visible":false}]},{"id":6728,"text":"Regarding glomerular diseases, which of the following is most likely the pathogenesis of glomerulonephritis?","explanation":null,"reference":null,"responses":[{"text":"Complement proteins do not play an important role in the pathogenesis","correct":false,"visible":false},{"text":"TGF-β released during nephritis leads to glomerular basement membrane thickening","correct":true,"visible":false},{"text":"In immune complex mediated nephritis, the autoantigen is characteristically glomerular","correct":false,"visible":false},{"text":"A causal role of T-cells in the pathogenesis has been strongly established by researchers","correct":false,"visible":false},{"text":"The pattern of antibody deposition in anti - GBM disease is radial in pattern","correct":false,"visible":false}]},{"id":6731,"text":"Which of the following drugs is ineffective in Addison's disease?","explanation":null,"reference":null,"responses":[{"text":"Amiloride","correct":false,"visible":false},{"text":"Hydrocortisone","correct":false,"visible":false},{"text":"Triamterene","correct":false,"visible":false},{"text":"Spironolactone","correct":true,"visible":false},{"text":"Bumetanide","correct":false,"visible":false}]},{"id":6732,"text":"What are the regions of cortical parenchyma located between medullary pyramids rather than adjacent to the surface of the kidney called?","explanation":null,"reference":null,"responses":[{"text":"Columns of Bertin","correct":true,"visible":false},{"text":"Papillae","correct":false,"visible":false},{"text":"Calyces","correct":false,"visible":false},{"text":"Medullary rays","correct":false,"visible":false},{"text":"Renal lobules","correct":false,"visible":false}]},{"id":6737,"text":"Which of the following is responsible for glucose reabsorption in the S1 segment of the proximal convoluted tubule?","explanation":null,"reference":null,"responses":[{"text":"GLUT2 (glucose transporter-2)","correct":false,"visible":false},{"text":"GLUT3 (glucose transporter-3)","correct":false,"visible":false},{"text":"GLUT1 (glucose transporter-1)","correct":false,"visible":false},{"text":"SGLT1 (sodium-glucose cotransporter-1)","correct":false,"visible":false},{"text":"SGLT2 (sodium-glucose cotransporter-2)","correct":true,"visible":false}]},{"id":6741,"text":"Which of the following drugs should be used to decrease intracranial pressure?","explanation":null,"reference":null,"responses":[{"text":"Mannitol","correct":true,"visible":false},{"text":"Fludrocortisone","correct":false,"visible":false},{"text":"Acetaminophen","correct":false,"visible":false},{"text":"Phenylephrine","correct":false,"visible":false},{"text":"Midodrine","correct":false,"visible":false}]},{"id":6744,"text":"Which of the following is not present anterior to the urinary bladder?","explanation":null,"reference":null,"responses":[{"text":"Pubic bones","correct":false,"visible":false},{"text":"Puboprostatic ligament","correct":false,"visible":false},{"text":"Body of uterus","correct":true,"visible":false},{"text":"Retropubic space","correct":false,"visible":false},{"text":"Pubo-vesical ligament","correct":false,"visible":false}]},{"id":6746,"text":"What does renal correction of acute hyperkalemia result in?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 415.","responses":[{"text":"Increased secretion of H+","correct":false,"visible":false},{"text":"Alkalosis","correct":false,"visible":false},{"text":"Acidosis","correct":true,"visible":false},{"text":"Increased secretion of Na+","correct":false,"visible":false},{"text":"Increased secretion of HCO3-","correct":false,"visible":false}]},{"id":6748,"text":"Sodium retention through aldosterone-mediated renal regulation results in the elimination of which one of the following?","explanation":null,"reference":null,"responses":[{"text":"HCO3- ions","correct":false,"visible":false},{"text":"NH3+ ions","correct":false,"visible":false},{"text":"Cl- ions","correct":false,"visible":false},{"text":"K+ ions","correct":true,"visible":false},{"text":"H+ ions","correct":false,"visible":false}]},{"id":6750,"text":"Where do the stretch signals for bladder emptying mainly originate?","explanation":null,"reference":null,"responses":[{"text":"Ureter","correct":false,"visible":false},{"text":"Fundus of urinary bladder","correct":false,"visible":false},{"text":"Body of the bladder","correct":false,"visible":false},{"text":"Anterior urethra","correct":false,"visible":false},{"text":"Posterior urethra","correct":true,"visible":false}]},{"id":6754,"text":"Which of the following will increase the ability of the kidney to excrete concentrated urine?","explanation":null,"reference":null,"responses":[{"text":"Increasing the rate of flow through the loop of Henle","correct":false,"visible":false},{"text":"Decreasing the rate of blood flow through the medulla","correct":true,"visible":false},{"text":"Decreasing the permeability of the proximal tubule to water","correct":false,"visible":false},{"text":"Decreasing the permeability of the collecting duct to water","correct":false,"visible":false},{"text":"Decreasing the activity of the Na-K pump in the loop of Henle","correct":false,"visible":false}]},{"id":6755,"text":"Which type of transport facilitates the sodium absorption in distal convoluted tubule by Na pump across the basolateral membrane?","explanation":null,"reference":null,"responses":[{"text":"Passive transport","correct":false,"visible":false},{"text":"Diffusion","correct":false,"visible":false},{"text":"Primary active transport","correct":true,"visible":false},{"text":"Facilitated diffusion","correct":false,"visible":false},{"text":"Secondary active transport","correct":false,"visible":false}]},{"id":6756,"text":"Which structure is not related to the anterior surface of the right kidney?","explanation":null,"reference":null,"responses":[{"text":"Right colic flexure","correct":false,"visible":false},{"text":"Spleen","correct":true,"visible":false},{"text":"Descending part of duodenum","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Suprarenal gland","correct":false,"visible":false}]},{"id":6757,"text":"Which of the following provides arterial supply to the pelvic part of the ureter?","explanation":"The **ureter** receives its blood supply from a variety of sources throughout its course due to its descending nature. For the pelvic part of the ureter, the primary source of blood supply is from branches of the **internal iliac artery**. Specifically, the **superior vesical artery**, a branch of the anterior trunk of the internal iliac artery, provides blood to the superior aspect of the bladder and the distal parts of the ureter.","reference":"Drake RL, Vogl W, Mitchell AWM, Gray H. Gray’s Anatomy for Students. 3rd ed. Churchill Livingstone/Elsevier; 2015: 496.","responses":[{"text":"Gonadal artery","correct":false,"visible":false},{"text":"Inferior vesical artery","correct":false,"visible":false},{"text":"Internal iliac artery","correct":true,"visible":false},{"text":"Abdominal aorta","correct":false,"visible":false},{"text":"Renal artery","correct":false,"visible":false}]},{"id":6758,"text":"What is the compensatory mechanism in respiratory acidosis (increased PCO2)?","explanation":null,"reference":null,"responses":[{"text":"Decrease in plasma bicarbonate (HCO3-) concentration","correct":false,"visible":false},{"text":"Increased oxygen saturation","correct":false,"visible":false},{"text":"Decreased levels of ammonia","correct":false,"visible":false},{"text":"Increase in plasma bicarbonate (HCO3-) concentration","correct":true,"visible":false},{"text":"Decreased respiratory rate","correct":false,"visible":false}]},{"id":6759,"text":"Which of the following do the afferent arterioles arise from?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 323.","responses":[{"text":"Intralobar artery","correct":false,"visible":false},{"text":"Interlobular artery","correct":true,"visible":false},{"text":"Interlobar artery","correct":false,"visible":false},{"text":"Peritubular capillaries","correct":false,"visible":false},{"text":"Arcuate artery","correct":false,"visible":false}]},{"id":6760,"text":"The distal part of the male urethra in the glans of the penis is derived from which of the following?","explanation":null,"reference":null,"responses":[{"text":"Endoderm","correct":false,"visible":false},{"text":"Lateral plate mesoderm","correct":false,"visible":false},{"text":"Intermediate mesoderm","correct":false,"visible":false},{"text":"Ectoderm","correct":true,"visible":false},{"text":"Paraxial mesoderm","correct":false,"visible":false}]},{"id":6761,"text":"Which of the following can the nephron be best defined as?","explanation":null,"reference":null,"responses":[{"text":"Glucose transporter","correct":false,"visible":false},{"text":"A structural and functional unit of kidney","correct":true,"visible":false},{"text":"Storage site of lipids","correct":false,"visible":false},{"text":"Site of ADH (antidiuretic hormone) production","correct":false,"visible":false},{"text":"Cholesterol synthesizing body","correct":false,"visible":false}]},{"id":6762,"text":"What is the end product of purine metabolism in humans?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 298.","responses":[{"text":"Hypoxanthine","correct":false,"visible":false},{"text":"Uric acid","correct":true,"visible":false},{"text":"Urea","correct":false,"visible":false},{"text":"Xanthine","correct":false,"visible":false},{"text":"Inositol","correct":false,"visible":false}]},{"id":6763,"text":"The examination of a cross-section of kidneys shows the renal columns of Bertin. Which statement best defines the renal columns of Bertin?","explanation":"The **renal columns of Bertin** are extensions of the renal cortex that project inward, intervening between the renal pyramids in the medulla of the kidney. They serve as a distinguishing feature when examining the internal structure of the kidney, particularly in a cross-sectional view. These columns essentially represent cortical tissue that dips into the medulla, dividing the medullary region into a series of triangular-shaped renal pyramids. The renal columns are mainly composed of the same tissue found in the renal cortex, including blood vessels and renal tubules, but they lack the glomeruli which are confined to the cortex.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 393.","responses":[{"text":"Cortical substance that extends into medulla","correct":true,"visible":false},{"text":"Medullary substance that extends into cortex","correct":false,"visible":false},{"text":"Nephrons that are drained by a common collecting duct","correct":false,"visible":false},{"text":"Marks beginning of nephron","correct":false,"visible":false},{"text":"Convoluted parts of renal tubules","correct":false,"visible":false}]},{"id":6764,"text":"Which of the following chemical substances inhibits the secretion of gastric acid?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 792.","responses":[{"text":"Gastrin","correct":false,"visible":false},{"text":"Secretin","correct":true,"visible":false},{"text":"Histamine","correct":false,"visible":false},{"text":"Gastric inhibitory peptide","correct":false,"visible":false},{"text":"Acetylcholine","correct":false,"visible":false}]},{"id":6765,"text":"The greatest amount of hydrogen ion secreted by the proximal tubule is associated with which of the following?","explanation":null,"reference":null,"responses":[{"text":"Excretion of hydrogen ion","correct":false,"visible":false},{"text":"Reabsorption of calcium ion","correct":false,"visible":false},{"text":"Excretion of potassium ion","correct":false,"visible":false},{"text":"Reabsorption of phosphate ion","correct":false,"visible":false},{"text":"Reabsorption of bicarbonate ion","correct":true,"visible":false}]},{"id":6766,"text":"In which of the following are Na-K-Cl cotransporters present in?","explanation":null,"reference":null,"responses":[{"text":"Thick ascending limb of the loop of Henle","correct":true,"visible":false},{"text":"Collecting duct","correct":false,"visible":false},{"text":"Distal convoluted tubules","correct":false,"visible":false},{"text":"Proximal convoluted tubules","correct":false,"visible":false},{"text":"Thin ascending limb of the loop of Henle","correct":false,"visible":false}]},{"id":6767,"text":"What is the large space, lined by transitional epithelium, which funnels urine into the ureter called?","explanation":null,"reference":null,"responses":[{"text":"Pelvis","correct":true,"visible":false},{"text":"Capsule","correct":false,"visible":false},{"text":"Hilum","correct":false,"visible":false},{"text":"Papillae","correct":false,"visible":false},{"text":"Calyx","correct":false,"visible":false}]},{"id":6768,"text":"Which of the following is the only part present in the medullary region?","explanation":null,"reference":null,"responses":[{"text":"Bowman's capsule","correct":false,"visible":false},{"text":"Proximal convoluted tubule","correct":false,"visible":false},{"text":"Loop of Henle","correct":true,"visible":false},{"text":"Distal convoluted tubule","correct":false,"visible":false},{"text":"Glomerulus","correct":false,"visible":false}]},{"id":6770,"text":"What is the most sensitive indicator of glomerular function?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 361.","responses":[{"text":"Serum urea","correct":false,"visible":false},{"text":"Serum creatinine","correct":false,"visible":false},{"text":"Serum ammonia","correct":false,"visible":false},{"text":"Urea clearance","correct":false,"visible":false},{"text":"Creatinine clearance","correct":true,"visible":false}]},{"id":6773,"text":"What is the normal glomerular capillary colloid osmotic pressure?","explanation":null,"reference":null,"responses":[{"text":"18 mmHg","correct":false,"visible":false},{"text":"32 mmHg","correct":true,"visible":false},{"text":"70 mmHg","correct":false,"visible":false},{"text":"10 mmHg","correct":false,"visible":false},{"text":"60 mmHg","correct":false,"visible":false}]},{"id":6774,"text":"What is the normal PO2 level in arterial blood?","explanation":null,"reference":null,"responses":[{"text":"22-26 mm of Hg","correct":false,"visible":false},{"text":"\u003c50 mm of Hg","correct":false,"visible":false},{"text":"\u003e100 mm of Hg","correct":false,"visible":false},{"text":"85-90 mm of Hg","correct":true,"visible":false},{"text":"35-45 mm of Hg","correct":false,"visible":false}]},{"id":6776,"text":"The osmolality of the proximal convoluted tubule is the same as that of plasma, due to the presence of water channels on the basolateral membrane that causes reabsorption of water. Which water channels are present in the basolateral membrane of proximal convoluted tubules?","explanation":null,"reference":null,"responses":[{"text":"Aquaporin-5","correct":false,"visible":false},{"text":"Aquaporin-3","correct":false,"visible":false},{"text":"Aquaporin-1","correct":true,"visible":false},{"text":"Aquaporin-4","correct":false,"visible":false},{"text":"Aquaporin-2","correct":false,"visible":false}]},{"id":6778,"text":"Which part of the nephron exhibits brush border on microscopy?","explanation":null,"reference":null,"responses":[{"text":"Proximal convoluted tubule","correct":true,"visible":false},{"text":"Distal convoluted tubule","correct":false,"visible":false},{"text":"Loop of Henle","correct":false,"visible":false},{"text":"Pars recta","correct":false,"visible":false},{"text":"Glomerulus","correct":false,"visible":false}]},{"id":6784,"text":"Which enzyme catalyzes the rate-limiting step of pyrimidine biosynthesis in mammalian cells?","explanation":null,"reference":null,"responses":[{"text":"Carbamoyl phosphate synthase II","correct":true,"visible":false},{"text":"Thymidylate synthase","correct":false,"visible":false},{"text":"Aspartate transcarbamoylase","correct":false,"visible":false},{"text":"Xanthine oxidase","correct":false,"visible":false},{"text":"Hypoxanthine-guanine phosphoribosyltransferase (HGPRT)","correct":false,"visible":false}]},{"id":6786,"text":"The severe constriction of efferent arterioles affects glomerular filtration rate (GFR) by which one of the following changes?","explanation":null,"reference":null,"responses":[{"text":"It has no effect on GFR","correct":false,"visible":false},{"text":"Decreases GFR by increasing colloid osmotic force","correct":true,"visible":false},{"text":"Increases renal blood flow by afferent arteriole vasodilatation","correct":false,"visible":false},{"text":"Increases GFR by increasing colloid osmotic force","correct":false,"visible":false},{"text":"Increases GFR by increasing renal flow","correct":false,"visible":false}]},{"id":6787,"text":"The substance is freely filtered at the glomerular capillaries but is not excreted into the urine because all the filtered substance is reabsorbed from the tubules back into the blood. This pattern occurs for which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 329.","responses":[{"text":"Bases","correct":false,"visible":false},{"text":"Inulin","correct":false,"visible":false},{"text":"Amino acids and glucose","correct":true,"visible":false},{"text":"Creatinine","correct":false,"visible":false},{"text":"Electrolytes","correct":false,"visible":false}]},{"id":6789,"text":"This substance is freely filtered at the glomerular capillaries and is not reabsorbed, but additional quantities of this substance are secreted from the peritubular capillary blood into the renal tubules. Which substance is this?","explanation":null,"reference":null,"responses":[{"text":"Inulin","correct":false,"visible":false},{"text":"Amino acids and glucose","correct":false,"visible":false},{"text":"Creatinine","correct":true,"visible":false},{"text":"Organic acids and bases","correct":false,"visible":false},{"text":"Electrolytes","correct":false,"visible":false}]},{"id":6791,"text":"This substance is freely filtered by the glomerular capillaries but is neither reabsorbed nor secreted. Therefore, its excretion rate is equal to the rate at which it was filtered. Which substance is this?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 355.","responses":[{"text":"Inulin","correct":true,"visible":false},{"text":"Amino acids","correct":false,"visible":false},{"text":"Electrolytes","correct":false,"visible":false},{"text":"Glucose","correct":false,"visible":false},{"text":"Creatinine","correct":false,"visible":false}]},{"id":6792,"text":"Under the influence of parathyroid hormone, the renal reabsorption of calcium mainly occurs in which part of the kidney?","explanation":null,"reference":"Costanzo L. Costanzo Physiology. 7th ed. Elsevier, Inc; 2021: 452.","responses":[{"text":"Distal convoluted tubule","correct":true,"visible":false},{"text":"Renal papilla","correct":false,"visible":false},{"text":"Ascending thick limb of loop of Henle","correct":false,"visible":false},{"text":"Vasa recta","correct":false,"visible":false},{"text":"Collecting ducts","correct":false,"visible":false}]},{"id":6794,"text":"What are the vessels that connect glomerular capillaries with peritubular capillaries called?","explanation":null,"reference":null,"responses":[{"text":"Afferent arterioles","correct":false,"visible":false},{"text":"Vasa recta","correct":false,"visible":false},{"text":"Peritubular capillaries","correct":false,"visible":false},{"text":"Arcuate arteries","correct":false,"visible":false},{"text":"Efferent arterioles","correct":true,"visible":false}]},{"id":6796,"text":"Which reflex is initiated when the ureter is blocked by the stone resulting in intense pain?","explanation":null,"reference":null,"responses":[{"text":"Vesico-ureteric reflex","correct":false,"visible":false},{"text":"Ureteric reflex","correct":false,"visible":false},{"text":"Reno-vesical reflex","correct":false,"visible":false},{"text":"Vesical reflex","correct":false,"visible":false},{"text":"Uretero-renal reflex","correct":true,"visible":false}]},{"id":6800,"text":"Which of the following is the correct sequence of branching pattern of renal arteries?","explanation":null,"reference":null,"responses":[{"text":"Segmental artery \u003e lobar artery \u003e intralobular artery \u003e arcuate artery","correct":false,"visible":false},{"text":"Segmental artery \u003e interlobar artery \u003e lobar artery \u003e arcuate artery","correct":false,"visible":false},{"text":"Lobar artery \u003e segmental artery \u003e interlobar artery \u003e arcuate artery","correct":false,"visible":false},{"text":"Lobar artery \u003e segmental artery \u003e intralobular artery \u003e arcuate artery","correct":false,"visible":false},{"text":"Segmental artery \u003e lobar artery \u003e interlobar artery \u003e arcuate artery","correct":true,"visible":false}]},{"id":6802,"text":"Which of the following is not the part of renal filtration barrier?","explanation":"The renal filtration barrier, crucial for selectively filtering blood, comprises three main components:\r\n\r\n1. **Fenestrated endothelium of glomerular capillaries:** These fenestrations allow easy passage of water, ions, and small molecules but block blood cells and larger proteins.\r\n \r\n2. **Basal lamina (or basement membrane):** A meshwork of glycoproteins and proteoglycans, it serves as a secondary filter, especially for negatively charged molecules.\r\n\r\n3. **Podocytes:** These cells have foot processes called pedicels, which interdigitate with one another, forming filtration slits that are covered by the slit diaphragm, a unique structure that further restricts the passage of large molecules.\r\n\r\nThe **continuous epithelium of glomerular capillaries** is not a component of the filtration barrier. The endothelium of glomerular capillaries is fenestrated, not continuous.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 389.","responses":[{"text":"Continuous epithelium of glomerular capillaries","correct":true,"visible":false},{"text":"Podocytes","correct":false,"visible":false},{"text":"Basal lamina","correct":false,"visible":false},{"text":"Endothelial cells","correct":false,"visible":false},{"text":"Fenestrated endothelium of glomerular capillaries","correct":false,"visible":false}]},{"id":6803,"text":"Which of the following study design is also called a snap shot study?","explanation":null,"reference":null,"responses":[{"text":"Case control study","correct":false,"visible":false},{"text":"Case series","correct":false,"visible":false},{"text":"Cohort study","correct":false,"visible":false},{"text":"Case report study","correct":false,"visible":false},{"text":"Cross-sectional study","correct":true,"visible":false}]},{"id":6805,"text":"Xanthine oxidase is catalytically important for the formation of uric acid along with which of these?","explanation":null,"reference":null,"responses":[{"text":"H2O","correct":false,"visible":false},{"text":"HCO3-","correct":false,"visible":false},{"text":"H2O2","correct":false,"visible":false},{"text":"CO2","correct":false,"visible":false},{"text":"O2","correct":true,"visible":false}]},{"id":6807,"text":"What is the renal capillary pressure across the glomerular capillaries?","explanation":null,"reference":null,"responses":[{"text":"50 mmHg","correct":false,"visible":false},{"text":"20 mmHg","correct":false,"visible":false},{"text":"10 mmHg","correct":false,"visible":false},{"text":"30 mmHg","correct":false,"visible":false},{"text":"60 mmHg","correct":true,"visible":false}]},{"id":6808,"text":"What is the major hormone involved in regulation of sodium and water balance in the body?","explanation":null,"reference":null,"responses":[{"text":"Vasopressin","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Aldosterone","correct":true,"visible":false},{"text":"Antidiuretic hormone","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false}]},{"id":6810,"text":"The superior portion of the ureter drains into which of the following lymph nodes?","explanation":null,"reference":null,"responses":[{"text":"Internal iliac nodes","correct":false,"visible":false},{"text":"Common iliac nodes","correct":false,"visible":false},{"text":"Lateral aortic nodes","correct":true,"visible":false},{"text":"Vesical nodes","correct":false,"visible":false},{"text":"External iliac nodes","correct":false,"visible":false}]},{"id":6815,"text":"Which of the following can be seen in the renal sinus?","explanation":null,"reference":null,"responses":[{"text":"Bowman's capsule","correct":false,"visible":false},{"text":"Glomerulus","correct":false,"visible":false},{"text":"Renal cortex","correct":false,"visible":false},{"text":"Renal pelvis","correct":true,"visible":false},{"text":"Medulla","correct":false,"visible":false}]},{"id":6816,"text":"Which of the following forms the outermost layer of the kidney?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 377.","responses":[{"text":"Fibrous capsule","correct":false,"visible":false},{"text":"Only fat","correct":false,"visible":false},{"text":"Perinephric fat","correct":false,"visible":false},{"text":"Peritoneum","correct":false,"visible":false},{"text":"Renal fascia","correct":true,"visible":false}]},{"id":6824,"text":"Which of the following is an acquired cause of vesicoureteral reflux in adults leading to urinary tract infection?","explanation":null,"reference":null,"responses":[{"text":"Spinal cord lesions","correct":true,"visible":false},{"text":"Bladder stones","correct":false,"visible":false},{"text":"Prostate hypertrophy","correct":false,"visible":false},{"text":"Bacterial infection","correct":false,"visible":false},{"text":"Kidney stones","correct":false,"visible":false}]},{"id":6825,"text":"Which of the following is not derived from ureteric bud?","explanation":null,"reference":null,"responses":[{"text":"Ureter","correct":false,"visible":false},{"text":"Bladder","correct":true,"visible":false},{"text":"Calyx","correct":false,"visible":false},{"text":"Renal pelvis","correct":false,"visible":false},{"text":"Collecting duct","correct":false,"visible":false}]},{"id":6830,"text":"Which of the following can not be used as a marker to measure glomerular filtration rate (GFR)?","explanation":null,"reference":null,"responses":[{"text":"Creatinine","correct":false,"visible":false},{"text":"Mannitol","correct":false,"visible":false},{"text":"Phenol red","correct":false,"visible":false},{"text":"Urea and nitrogen","correct":true,"visible":false},{"text":"Inulin","correct":false,"visible":false}]},{"id":6832,"text":"Which of the following is measured through the arterial blood gas (ABG) test?","explanation":null,"reference":null,"responses":[{"text":"Anion gap","correct":false,"visible":false},{"text":"pH, pCO2 and pO2","correct":true,"visible":false},{"text":"Oxygen saturation","correct":false,"visible":false},{"text":"Creatinine level","correct":false,"visible":false},{"text":"pCO2 and pO2","correct":false,"visible":false}]},{"id":6834,"text":"Which of the following correctly describes 'informational care'?","explanation":null,"reference":null,"responses":[{"text":"Provision of information to patients about disease","correct":false,"visible":false},{"text":"Provision of information to patients about drugs and their side effects","correct":false,"visible":false},{"text":"Provision of information to patients about doctors","correct":false,"visible":false},{"text":"Provision of information to patients about disease, drugs, and doctors","correct":true,"visible":false},{"text":"Provision of information to patients about drugs and doctors","correct":false,"visible":false}]},{"id":6836,"text":"Which of the following is most true for transplantation?","explanation":null,"reference":null,"responses":[{"text":"Polycystic kidneys should be excluded from the list of allografts","correct":true,"visible":false},{"text":"HIV is the most contraindicated","correct":false,"visible":false},{"text":"Quality of life is increased after transplantation","correct":false,"visible":false},{"text":"Renal transplantation is reasonable for all end-stage renal diseases","correct":false,"visible":false},{"text":"Graft reaction occurs in poor patients","correct":false,"visible":false}]},{"id":6837,"text":"A patient came to the outpatient department with frequent urinary discharge. A complete urinalysis on agar medium was done and bacteria were found to be non-lactose fermenter, gram -ve, rod-shaped with no signs of swarming movement. Which of the following could be the cause?","explanation":null,"reference":null,"responses":[{"text":"Proteus mirabilis","correct":false,"visible":false},{"text":"Enterococcus","correct":false,"visible":false},{"text":"E.coli","correct":false,"visible":false},{"text":"Pseudomonas","correct":true,"visible":false},{"text":"Proteus vulgaris","correct":false,"visible":false}]},{"id":6838,"text":"Which of the following drugs is effective in decreasing K+ ion secretion in the distal convoluted tubule?","explanation":null,"reference":null,"responses":[{"text":"Potassium-sparing diuretic","correct":true,"visible":false},{"text":"Metronidazole","correct":false,"visible":false},{"text":"Thiazide diuretics","correct":false,"visible":false},{"text":"Acetaminophen","correct":false,"visible":false},{"text":"Loop diuretics","correct":false,"visible":false}]},{"id":6839,"text":"Which of the following is involved in the counter-current multiplier mechanism of kidneys?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 368.","responses":[{"text":"Vasa recta","correct":false,"visible":false},{"text":"Proximal convoluted tubules","correct":false,"visible":false},{"text":"Peritubular arteries","correct":false,"visible":false},{"text":"Glomerulus","correct":false,"visible":false},{"text":"Loop of Henle","correct":true,"visible":false}]},{"id":6840,"text":"Which of the following is the normal value of filtration fraction?","explanation":null,"reference":null,"responses":[{"text":"10%","correct":false,"visible":false},{"text":"15%","correct":false,"visible":false},{"text":"7%","correct":false,"visible":false},{"text":"20%","correct":true,"visible":false},{"text":"5%","correct":false,"visible":false}]},{"id":6841,"text":"Which of the following is not found anterior to the left kidney?","explanation":null,"reference":null,"responses":[{"text":"Head of pancreas","correct":true,"visible":false},{"text":"Spleen","correct":false,"visible":false},{"text":"Suprarenal gland","correct":false,"visible":false},{"text":"Looped jejenum","correct":false,"visible":false},{"text":"Splenic flexure","correct":false,"visible":false}]},{"id":6842,"text":"Which of the following parts of the bladder expands when it is filled up completely?","explanation":null,"reference":null,"responses":[{"text":"Trigone","correct":true,"visible":false},{"text":"Neck","correct":false,"visible":false},{"text":"Base","correct":false,"visible":false},{"text":"Fundus","correct":false,"visible":false},{"text":"Body","correct":false,"visible":false}]},{"id":6852,"text":"A 20-year-old man is brought into the emergency as he has overdosed on morphine. On examination, he is unconscious, pupils are pinpoint and nonreactive. Several injection marks are also seen on his arms. What is the immediate treatment to be precise after seeing breathing, and circulation?","explanation":null,"reference":null,"responses":[{"text":"Naloxone","correct":true,"visible":false},{"text":"Naloxone + gastric lavage","correct":false,"visible":false},{"text":"Gastric lavage","correct":false,"visible":false},{"text":"Gastric lavage with tannic acid","correct":false,"visible":false},{"text":"Naloxone + pethidine","correct":false,"visible":false}]},{"id":6934,"text":"A couple married for four years was unable to conceive a pregnancy. A detailed analysis of the sperms of the husband revealed azoospermia. They were suggested to go for artificial insemination by a fertility specialist. Which type of procedure would best suit the couple?","explanation":null,"reference":null,"responses":[{"text":"Artificial insemination donor","correct":true,"visible":false},{"text":"Artificial insemination homologous","correct":false,"visible":false},{"text":"Surrogacy","correct":false,"visible":false},{"text":"In vitro fertilization","correct":false,"visible":false},{"text":"Artificial insemination","correct":false,"visible":false}]},{"id":16012,"text":"Which of the following hormones or autocoids can increase the glomerular filtration rate (GFR) by decreasing vascular resistance in the glomerular capillaries?","explanation":"The glomerular filtration rate (GFR) is influenced by the balance between vasoconstrictor and vasodilator factors acting on the afferent and efferent arterioles of the renal glomerulus. Endothelial derived nitric oxide (NO) is a potent vasodilator. It decreases the vascular resistance of the glomerular capillaries by relaxing the vascular smooth muscle cells. This relaxation results in vasodilation of the afferent arterioles, leading to an increased renal blood flow and consequently a higher GFR. On the contrary, agents like norepinephrine, epinephrine, and angiotensin II predominantly cause vasoconstriction, which can decrease GFR. Angiotensin I is a precursor to angiotensin II and by itself does not have significant vasoactive properties.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 338.","responses":[{"text":"Angiotensin II","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Angiotensin I","correct":false,"visible":false},{"text":"Endothelial derived nitric oxide","correct":true,"visible":false}]}
]

export default a